value.value:
@if( equals(string(coalesce(item()?.condition, 'notFound')), 'notFound'), true,
  if(
    contains(
	  string(pipeline().parameters.previousOutputs),
	  concat('"', coalesce(item()?.condition?.name, 'name_notFound'), '"') 
	 ),
	 if(
	   contains(
	     string(json(pipeline().parameters.previousOutputs)[item().condition.name]),
		 concat('"', coalesce(item()?.condition?.internal_name, item().condition.name), '"')
	   ),
	   if(
	     contains(string(json(pipeline().parameters.previousOutputs)
		                 [item().condition.name]
						 [coalesce(item()?.condition?.internal_name, item().condition.name)]
		                ),
		          concat('"', coalesce(item()?.condition?.key, 'keyNotFound'), '"')
		 ),
		 contains(string(json(pipeline().parameters.previousOutputs)
		                     [item().condition.name]
		                     [coalesce(item()?.condition?.internal_name, item().condition.name)]
							 [item().condition.key]),
		          item().condition.value),
	   false),
	 false),  
  false))
